const airtableRecord = $('11. Retrieve latest script').first().json;
const telegramData = $('9. Bara sends recording').first().json;
const videoFilePath = $('10. Get video file path').first().json.result.file_path;

const script = airtableRecord.fields.Script;
const recordId = airtableRecord.id;

// Extract title from first lines of script
const lines = script.split('\n').filter(l => l.trim());
const titleLine = lines.find(l => l.length > 20 && l.length < 100) || lines[0];
const videoTitle = titleLine.replace(/[#*_]/g, '').trim().substring(0, 80);

const videoUrl = `https://api.telegram.org/file/bot${process.env.TELEGRAM_TOKEN}/${videoFilePath}`;

return [{
  json: {
    script,
    recordId,
    videoTitle,
    videoUrl,
    chatId: telegramData.message.chat.id,
    mainKeyword: 'AI proof business career future'
  }
}];

