// n8n Function Node: Apollo Random Filter Generator (Working Industries + Market Segment)

const TITLES = ["CEO","Founder","Co-founder","CMO","Owner"];
const LOCATIONS = ["United States","United Kingdom","Australia","Canada","UAE","Ireland","Singapore","Hong Kong","New Zealand"];
const COMPANY_SIZES = ["1,10","11,20","21,50","51,100","101,200","201,500"];
const MARKET_SEGMENTS = ["B2B","B2C","B2B2C","E-commerce","Fintech","D2C","Non-Profit","SaaS","Consulting","Services","Retail"];

// Only industries with free-plan IDs (example IDs, replace with Apollo’s current IDs)
const INDUSTRY_IDS = [
  "556c938d7261693b2b1d0001", // Education
  "556c938d7261693b2b1d0002", // Healthcare
  "556c938d7261693b2b1d0003", // Finance
  "556c938d7261693b2b1d0004", // Technology
  "556c938d7261693b2b1d0005", // Retail
  "556c938d7261693b2b1d0006"  // Non-Profit
];

// helper to pick random subset
function pickRandomSubset(arr, max=3) {
    const shuffled = [...arr].sort(() => Math.random() - 0.5);
    const count = Math.floor(Math.random() * max) + 1;
    return shuffled.slice(0, count);
}

// encode key[]=value1&key[]=value2
function encodeParams(key, arr) {
    return arr.map(v => `${key}[]=${encodeURIComponent(v)}`).join("&");
}

const randomTitles = pickRandomSubset(TITLES, 3);
const randomLocations = pickRandomSubset(LOCATIONS, 4);
const randomSizes = pickRandomSubset(COMPANY_SIZES, 3);
const randomMarkets = pickRandomSubset(MARKET_SEGMENTS, 2);
const randomIndustries = pickRandomSubset(INDUSTRY_IDS, 1); // pick only 1 industry for stability

let base = "https://app.apollo.io/#/people?";
let params = [];

params.push(encodeParams("personTitles", randomTitles));
params.push(encodeParams("personLocations", randomLocations));
params.push(encodeParams("organizationNumEmployeesRanges", randomSizes));
params.push(encodeParams("industry_ids", randomIndustries)); // working industry IDs
params.push(encodeParams("marketSegments", randomMarkets));
params.push("recommendationConfigId=score");
params.push("sortAscending=false");
params.push("sortByField=%5Bnone%5D");

const url = base + params.join("&");

// Output the generated URL in JSON
return [{ json: { apolloUrl: url } }];

const text = $input.first().json.output;
const chunkSize = 2000;
const richTextChunks = [];

for (let i = 0; i < text.length; i += chunkSize) {
  richTextChunks.push({
    text: { content: text.slice(i, i + chunkSize) }
  });
}

return [{
  json: {
    ...$input.first().json,
    richTextChunks
  }
}];

