// Collect all input items (one item per connected upload node)
const inputs = $input.all();

// Map to array of objects CraftMyPdf expects: { url: "https://..." }
const urls = inputs.map(item => {
  // prefer webViewLink, fallback to constructing a Drive view link from id
  const webView = item.json.webViewLink || (item.json.id ? `https://drive.google.com/file/d/${item.json.id}/view` : null);
  return { url: webView };
}).filter(u => u.url); // drop any missing links

// Output a single item whose json.urls is the array
return [{ json: { urls } }];

const afterImageUrl = $input.first().json.AfterImageUrl;
const beforeImageUrl = $input.last().json.BeforeImageUrl;

const html = '<!DOCTYPE html>' +
'<html lang="en"><head><meta charset="UTF-8"><style>' +
'* { margin: 0; padding: 0; box-sizing: border-box; }' +
'html, body { height: 2500px; overflow: hidden; background-color: #e8e8e8; display: flex; justify-content: center; align-items: flex-start; gap: 40px; padding: 30px 0px 0px; }' +
'.card { width: 1200px; height: 2400px; overflow: hidden; box-shadow: 0 20px 60px rgba(0,0,0,0.15); background: #fff; }' +
'.card img { width: 100%; height: 100%; object-fit: cover; object-position: top; display: block; }' +
'</style></head><body>' +
'<div class="card"><img src="' + afterImageUrl + '" alt="After" /></div>' +
'<div class="card"><img src="' + beforeImageUrl + '" alt="Before" /></div>' +
'</body></html>';

return [{ json: { html } }];

const fileId = $input.first().json.id;
const AfterImageUrl = 'https://drive.google.com/thumbnail?id=' + fileId + '&sz=w4000';

return [{ json: { AfterImageUrl } }];

const fileId = $input.first().json.id;
const BeforeImageUrl = 'https://drive.google.com/thumbnail?id=' + fileId + '&sz=w4000';

return [{ json: { BeforeImageUrl } }];

return items.map(item => {
  const domain = $('Search files and folders').first().json.name || '';

  // Remove everything after the first dot
  const companyName = domain.split('.')[0];

  return {
    json: {
      companyName
    }
  };
});

return items.map(item => {
  const email = $input.first().json.properties.email || '';

  // Extract domain after @
  const domain = email.split('@')[1] || '';

  // Build https link
  const website = domain ? `https://${domain}` : '';

  return {
    json: {
      website
    }
  };
});

// Require images Code node
// If either image URL is missing, return [] to stop the rest of the workflow.

const after = $input.first().json.AfterImageUrl;
const before = $input.last().json.BeforeImageUrl;

// If either is falsy (undefined, null, empty string), stop here
if (!after || !before) {
  // Optional: set a useful output for logs or Slack if you want:
  // return [{ json: { stopped: true, reason: 'Missing image(s)' } }];
  return []; // returning no items prevents downstream nodes from running
}

// Both images exist — continue the normal flow
return items;

