    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  cleanedOutput = cleanedOutput.replace(/[\u0000-\u001F\u007F]/g, '');

  const carouselData = JSON.parse(cleanedOutput);

  // Get slide index from workflow parameter (1 = slide 1, etc.)
  const slideIndex = 5 || 1; // fallback to 1 if not provided

  if (!carouselData.slides[slideIndex - 1]) {
    throw new Error(`Slide index ${slideIndex} does not exist`);
  }

  const slide = carouselData.slides[slideIndex - 1];

  const formatBody = (text) => {
    if (!text) return '';
    return text
      .split(/(?<=\.)\s+|(?<=\d\.)\s+|(?<=[-*])\s+/)
      .map(part => part.trim())
      .filter(part => part !== '')
      .join('<br><br>');
  };

  return [{
    json: {
      slideNumber: slideIndex,
      totalSlides: carouselData.slides.length,
      subtitle: `Slide ${slideIndex}/${carouselData.slides.length}`,
      title: slide.title,
      body: formatBody(slide.body),
      cta: slide.cta || '',
      isFirstSlide: slideIndex === 1,
      isLastSlide: slideIndex === carouselData.slides.length,
      post_text: carouselData.post_text
    }
  }];

} catch (error) {
  return [{
    json: {
      error: error.message,
      rawInput: $input.first().json.output[0].content[0].text
    }
  }];
}

