const items = $input.all();

return items.map(item => {
  const fromRaw = item.json.From || "";

  let email = "";
  let firstName = "";
  let lastName = "";

  // Case 1: Format "Name <email>"
  const emailMatch = fromRaw.match(/<([^>]+)>/);
  if (emailMatch) {
    email = emailMatch[1].trim();

    const nameOnly = fromRaw.replace(/<.*?>/g, "").trim();
    if (nameOnly) {
      const parts = nameOnly.split(/\s+/);
      firstName = parts.shift() || "";
      lastName = parts.join(" ") || "";
    }

  } else {
    // Case 2: Just an email alone
    const simpleMatch = fromRaw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
    email = simpleMatch ? simpleMatch[0].trim() : "";
  }

  // Build output dynamically (only include names if they exist)
  const output = {
    ...item.json,
    email
  };

  if (firstName) output.firstname = firstName;
  if (lastName) output.lastname = lastName;

  return { json: output };
});

// Combine all incoming items from all connections
const allItems = $input.all();

// Helper to safely read property values (handles HubSpot shapes)
function readProp(obj, keys) {
    if (!obj) return null;

    // direct props on item.json
    for (const k of keys) {
        if (Object.prototype.hasOwnProperty.call(obj, k)) {
            const v = obj[k];
            if (v && typeof v === 'object' && Object.prototype.hasOwnProperty.call(v, 'value')) return v.value;
            return v;
        }
    }

    // nested under item.json.properties (HubSpot)
    if (obj.properties && typeof obj.properties === 'object') {
        for (const k of keys) {
            if (Object.prototype.hasOwnProperty.call(obj.properties, k)) {
                const v = obj.properties[k];
                if (v && typeof v === 'object' && Object.prototype.hasOwnProperty.call(v, 'value')) return v.value;
                return v;
            }
        }
    }

    return null;
}

// Parse stage into usable value
function parseStage(val) {
    if (val === undefined || val === null) return null;
    if (typeof val === 'number') return Number(val);
    const s = String(val).trim();
    if (!s.length) return null;
    const asNum = Number(s);
    return Number.isNaN(asNum) ? s : asNum;
}

// Separate HubSpot contact items vs Gmail trigger items
const hubspotItems = allItems.filter(it => {
    const j = it.json || {};
    return j.properties && Object.keys(j.properties).length > 0;
});

const triggerItems = allItems.filter(it => {
    const j = it.json || {};
    const looksLikeHubspot = j.properties && Object.keys(j.properties).length > 0;
    const looksLikeGmail = !!(j.from || j.threadId || j.id && j.raw && j.payload) || !!j.text;
    return !looksLikeHubspot && looksLikeGmail;
});

// If no HubSpot contact found, just return the Gmail trigger item
if (!hubspotItems.length) {
    if (triggerItems.length) return [triggerItems[0]];
    return allItems.length ? [allItems[0]] : [];
}

// Use first HubSpot contact result (search result)
const contactItem = hubspotItems[0].json;

// Read follow_up_stage from multiple possible keys
const stageRaw = readProp(contactItem, [
    'follow_up_stage',
    'followup_stage',
    'followupStage',
    'properties.follow_up_stage'
]);

const stageVal = parseStage(stageRaw);

// Always continue workflow (no stop logic)
if (triggerItems.length) return [triggerItems[0]];
return [hubspotItems[0]];

